"crm.formula.desc3": "\u05de\u05d7\u05d6\u05d9\u05e8\u05d4 \u05d0\u05ea \u05d4\u05de\u05e1\u05e4\u05e8 \u05d4\u05e9\u05dc\u05dd \u05d4\u05d2\u05d3\u05d5\u05dc \u05d1\u05d9\u05d5\u05ea\u05e8 \u05e9\u05e7\u05d8\u05df \u05de, \u05d0\u05d5 \u05e9\u05d5\u05d5\u05d4 \u05dc\u05de\u05e1\u05e4\u05e8 \u05d4\u05e7\u05dc\u05d8.",
"crm.formula.desc2": "\u05de\u05d7\u05d6\u05d9\u05e8\u05d4 \u05d0\u05ea \u05d4\u05de\u05e1\u05e4\u05e8 \u05d4\u05e9\u05dc\u05dd \u05d4\u05e7\u05d8\u05df \u05d1\u05d9\u05d5\u05ea\u05e8 \u05e9\u05d2\u05d3\u05d5\u05dc \u05de, \u05d0\u05d5 \u05e9\u05d5\u05d5\u05d4 \u05dc\u05de\u05e1\u05e4\u05e8 \u05d4\u05e7\u05dc\u05d8.",
