"crm.mb.field.label.dplk": "\u05E0\u05DE\u05E6\u05D0\u05D4 \u05DB\u05E4\u05D9\u05DC\u05D5\u05EA \u05D1\u05EA\u05D5\u05D5\u05D9\u05EA \u05D4\u05E9\u05D3\u05D4. \u05E0\u05D0 \u05DC\u05D4\u05D6\u05D9\u05DF \u05EA\u05D5\u05D5\u05D9\u05EA \u05D9\u05D9\u05D7\u05D5\u05D3\u05D9\u05EA.",
